-- Migration: Create home_master_curriculum table with 66 curated Montessori home works
-- Description: Master reference table for all 66 home Montessori works across 5 curriculum areas
-- This table stores the complete curriculum definition for the home Montessori learning environment

-- Create table
CREATE TABLE IF NOT EXISTS public.home_master_curriculum (
  id TEXT PRIMARY KEY,
  work_name TEXT NOT NULL,
  area_key TEXT NOT NULL,
  area_name TEXT NOT NULL,
  area_icon TEXT,
  area_color TEXT,
  description TEXT,
  age_range TEXT DEFAULT '3-6',
  sequence INTEGER,
  home_sequence INTEGER NOT NULL,
  home_priority TEXT NOT NULL DEFAULT 'recommended',
  home_tip TEXT,
  buy_or_make TEXT,
  estimated_cost TEXT,
  home_age_start TEXT,
  materials JSONB DEFAULT '[]'::jsonb,
  direct_aims JSONB DEFAULT '[]'::jsonb,
  indirect_aims JSONB DEFAULT '[]'::jsonb,
  control_of_error TEXT,
  prerequisites JSONB DEFAULT '[]'::jsonb,
  levels JSONB DEFAULT '[]'::jsonb,
  is_active BOOLEAN DEFAULT true,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Create index on area_key for efficient filtering
CREATE INDEX IF NOT EXISTS idx_home_master_curriculum_area_key ON public.home_master_curriculum(area_key);

-- Enable Row Level Security
ALTER TABLE public.home_master_curriculum ENABLE ROW LEVEL SECURITY;

-- Create RLS policy for service_role (full access)
DROP POLICY IF EXISTS service_role_policy_home_master_curriculum ON public.home_master_curriculum;
CREATE POLICY service_role_policy_home_master_curriculum
  ON public.home_master_curriculum
  FOR SELECT
  TO service_role
  USING (true);

-- Create RLS policy for anon role (read-only)
DROP POLICY IF EXISTS anon_policy_home_master_curriculum ON public.home_master_curriculum;
CREATE POLICY anon_policy_home_master_curriculum
  ON public.home_master_curriculum
  FOR SELECT
  TO anon
  USING (is_active = true);

-- Add comment to table
COMMENT ON TABLE public.home_master_curriculum IS 'Master reference table for 66 curated Montessori home curriculum works spanning Practical Life, Sensorial, Mathematics, Language, and Cultural Studies areas. Each work includes complete details on materials, aims, levels, costs, and implementation guidance for home learning environments.';

